func schemaFields(value reflect.Type) ([]fieldSchema, error) {
	fields := make([]fieldSchema, 0, value.NumField())
	for i := 0; i < value.NumField(); i++ {
		field := value.Field(i)
		jsonName, optional, ok := jsonField(field)
		if !ok {
