  console.log(`Reusing better-ao backend at ${backendOrigin}`);
  holdOpen();
} else if (hasCommand('go', ['version'])) {
  run('go', backendArgs);
} else if (process.platform !== 'win32' && hasCommand('nix', ['--version'])) {
  run('nix', ['develop', '--command', 'go', ...backendArgs]);
} else {
  console.error(
